const express = require('express');
const { Client } = require('@elastic/elasticsearch');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json({ limit: '10mb' }));

const esClient = new Client({
  node: process.env.ELASTICSEARCH_URL || 'http://localhost:9200',
  auth: {
    username: process.env.ES_USERNAME || 'elastic',
    password: process.env.ES_PASSWORD || 'changeme'
  }
});

function buildBaseQuery(searchParams) {
  const { query, filters, fields, fuzzy, boost } = searchParams;
  
  let baseQuery = { bool: { must: [], filter: [], should: [] } };

  if (query) {
    if (fields && fields.length > 0) {
      const multiMatchQuery = {
        multi_match: {
          query: query,
          fields: fields,
          type: fuzzy ? 'best_fields' : 'most_fields',
          fuzziness: fuzzy ? 'AUTO' : undefined
        }
      };
      
      if (boost) {
        multiMatchQuery.multi_match.boost = boost;
      }
      
      baseQuery.bool.must.push(multiMatchQuery);
    } else {
      baseQuery.bool.must.push({
        query_string: {
          query: query,
          default_operator: 'AND'
        }
      });
    }
  }

  if (filters) {
    if (filters.term) {
      Object.entries(filters.term).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ term: { [field]: value } });
      });
    }

    if (filters.range) {
      Object.entries(filters.range).forEach(([field, rangeValues]) => {
        baseQuery.bool.filter.push({ range: { [field]: rangeValues } });
      });
    }

    if (filters.match) {
      Object.entries(filters.match).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ match: { [field]: value } });
      });
    }

    if (filters.exists) {
      filters.exists.forEach(field => {
        baseQuery.bool.filter.push({ exists: { field: field } });
      });
    }

    if (filters.wildcard) {
      Object.entries(filters.wildcard).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ wildcard: { [field]: value } });
      });
    }

    if (filters.prefix) {
      Object.entries(filters.prefix).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ prefix: { [field]: value } });
      });
    }

    if (filters.regexp) {
      Object.entries(filters.regexp).forEach(([field, value]) => {
        baseQuery.bool.filter.push({ regexp: { [field]: value } });
      });
    }

    if (filters.geo_distance) {
      baseQuery.bool.filter.push({ geo_distance: filters.geo_distance });
    }

    if (filters.nested) {
      filters.nested.forEach(nestedFilter => {
        baseQuery.bool.filter.push({ nested: nestedFilter });
      });
    }
  }

  if (baseQuery.bool.must.length === 0 && 
      baseQuery.bool.filter.length === 0 && 
      baseQuery.bool.should.length === 0) {
    return { match_all: {} };
  }

  return baseQuery;
}

function buildScriptScoreQuery(baseQuery, scriptConfig) {
  const { source, lang, params } = scriptConfig;

  return {
    script_score: {
      query: baseQuery,
      script: {
        source: source,
        lang: lang || 'painless',
        params: params || {}
      },
      min_score: scriptConfig.min_score,
      boost: scriptConfig.boost
    }
  };
}

function buildFunctionScoreQuery(baseQuery, functionConfig) {
  const functionScoreQuery = {
    function_score: {
      query: baseQuery,
      functions: [],
      score_mode: functionConfig.score_mode || 'multiply',
      boost_mode: functionConfig.boost_mode || 'multiply',
      max_boost: functionConfig.max_boost,
      min_score: functionConfig.min_score
    }
  };

  if (functionConfig.functions) {
    functionConfig.functions.forEach(func => {
      const functionDef = {};

      if (func.filter) {
        functionDef.filter = func.filter;
      }

      if (func.weight) {
        functionDef.weight = func.weight;
      }

      if (func.script_score) {
        functionDef.script_score = {
          script: {
            source: func.script_score.source,
            lang: func.script_score.lang || 'painless',
            params: func.script_score.params || {}
          }
        };
      }

      if (func.field_value_factor) {
        functionDef.field_value_factor = func.field_value_factor;
      }

      if (func.random_score) {
        functionDef.random_score = func.random_score;
      }

      if (func.decay_function) {
        const decayType = func.decay_function.type || 'gauss';
        functionDef[decayType] = func.decay_function.config;
      }

      functionScoreQuery.function_score.functions.push(functionDef);
    });
  }

  return functionScoreQuery;
}

function buildAggregations(aggConfig) {
  if (!aggConfig) return undefined;

  const aggregations = {};

  if (aggConfig.terms) {
    aggConfig.terms.forEach(termAgg => {
      aggregations[termAgg.name] = {
        terms: {
          field: termAgg.field,
          size: termAgg.size || 10,
          order: termAgg.order
        }
      };
    });
  }

  if (aggConfig.date_histogram) {
    aggConfig.date_histogram.forEach(dateAgg => {
      aggregations[dateAgg.name] = {
        date_histogram: {
          field: dateAgg.field,
          calendar_interval: dateAgg.interval,
          format: dateAgg.format,
          min_doc_count: dateAgg.min_doc_count
        }
      };
    });
  }

  if (aggConfig.stats) {
    aggConfig.stats.forEach(statsAgg => {
      aggregations[statsAgg.name] = {
        stats: {
          field: statsAgg.field
        }
      };
    });
  }

  if (aggConfig.range) {
    aggConfig.range.forEach(rangeAgg => {
      aggregations[rangeAgg.name] = {
        range: {
          field: rangeAgg.field,
          ranges: rangeAgg.ranges
        }
      };
    });
  }

  if (aggConfig.nested) {
    aggConfig.nested.forEach(nestedAgg => {
      aggregations[nestedAgg.name] = {
        nested: {
          path: nestedAgg.path
        },
        aggs: nestedAgg.aggs
      };
    });
  }

  if (aggConfig.custom) {
    Object.entries(aggConfig.custom).forEach(([name, config]) => {
      aggregations[name] = config;
    });
  }

  return Object.keys(aggregations).length > 0 ? aggregations : undefined;
}

app.post('/api/search', async (req, res) => {
  try {
    const {
      index,
      searchParams,
      scriptScore,
      functionScore,
      aggregations,
      sort,
      from,
      size,
      source,
      highlight
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    const baseQuery = buildBaseQuery(searchParams || {});
    
    let finalQuery = baseQuery;

    if (scriptScore) {
      finalQuery = buildScriptScoreQuery(baseQuery, scriptScore);
    } else if (functionScore) {
      finalQuery = buildFunctionScoreQuery(baseQuery, functionScore);
    }

    const searchBody = {
      query: finalQuery,
      from: from || 0,
      size: size || 10
    };

    if (sort) {
      searchBody.sort = sort;
    }

    if (source !== undefined) {
      searchBody._source = source;
    }

    if (highlight) {
      searchBody.highlight = highlight;
    }

    const aggs = buildAggregations(aggregations);
    if (aggs) {
      searchBody.aggs = aggs;
    }

    const result = await esClient.search({
      index: index,
      body: searchBody
    });

    res.json({
      took: result.took,
      total: result.hits.total,
      max_score: result.hits.max_score,
      hits: result.hits.hits.map(hit => ({
        _id: hit._id,
        _score: hit._score,
        _source: hit._source,
        highlight: hit.highlight,
        sort: hit.sort
      })),
      aggregations: result.aggregations
    });

  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({
      error: 'Search failed',
      message: error.message,
      details: error.meta?.body?.error
    });
  }
});

