app.post('/api/search/multi', async (req, res) => {
  try {
    const { searches } = req.body;

    if (!searches || !Array.isArray(searches)) {
      return res.status(400).json({ error: 'Searches array is required' });
    }

    const body = searches.flatMap(search => [
      { index: search.index },
      search.body
    ]);

    const result = await esClient.msearch({ body });

    res.json({
      responses: result.responses.map((response, index) => ({
        searchId: searches[index].id || index,
        took: response.took,
        total: response.hits?.total,
        hits: response.hits?.hits,
        aggregations: response.aggregations,
        error: response.error
      }))
    });

  } catch (error) {
    console.error('Multi-search error:', error);
    res.status(500).json({
      error: 'Multi-search failed',
      message: error.message
    });
  }
});

